patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index e7b52fbdcc3b..865be45b3847 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -9483,7 +9483,11 @@ void BoUpSLP::transformNodes() {
         }
       }
     }
-    switch (E.getOpcode()) {
+            // Do not demote/sink truncations across llvm.abs intrinsic. Changing the
+        // operand bitwidth of abs can alter semantics (e.g., computing abs in i32
+        // instead of original i64 before trunc). Preserve abs width by treating it
+        // as a barrier for truncation sinking.
+switch (E.getOpcode()) {
     case Instruction::Load: {
       // No need to reorder masked gather loads, just reorder the scalar
       // operands.
@@ -11065,7 +11069,7 @@ BoUpSLP::getEntryCost(const TreeEntry *E, ArrayRef<Value *> VectorizedVals,
   case Instruction::URem:
   case Instruction::SRem:
   case Instruction::FRem:
-  case Instruction::Shl:
+case Instruction::Shl:
   case Instruction::LShr:
   case Instruction::AShr:
   case Instruction::And:
@@ -17077,9 +17081,17 @@ bool BoUpSLP::collectValuesToDemote(
         ToDemote.push_back(E.Idx);
         return IsProfitableToDemote;
       };
+        // Do not demote/sink truncations across llvm.abs intrinsic. Changing the
+        // operand bitwidth of abs can alter semantics (e.g., computing abs in i32
+        // instead of original i64 before trunc). Preserve abs width by treating it
+        // as a barrier for truncation sinking.
   switch (E.getOpcode()) {

   // We can always demote truncations and extensions. Since truncations can
+    // Do not demote/sink truncations across llvm.abs intrinsic. Changing the
+    // operand bitwidth of abs can alter semantics (e.g., computing abs in i32
+    // instead of original i64 before trunc). Preserve abs width by treating it
+    // as a barrier for truncation sinking.
   // seed additional demotion, we save the truncated value.
   case Instruction::Trunc:
     if (IsProfitableToDemoteRoot)
@@ -17190,6 +17202,19 @@ bool BoUpSLP::collectValuesToDemote(
     if (!IC)
       break;
     Intrinsic::ID ID = getVectorIntrinsicIDForCall(IC, TLI);
+
+    // For abs, avoid demotion if the operand is produced by operations that
+    // can overflow when narrowed (e.g., mul/shl). Narrowing abs in such cases
+    // may change semantics (compute abs in narrower type). Conservatively bail.
+    if (ID == Intrinsic::abs) {
+      const TreeEntry *Op0TE = getOperandEntry(&E, 0);
+      if (Op0TE && (Op0TE->getOpcode() == Instruction::Mul ||
+                    Op0TE->getOpcode() == Instruction::Shl))
+        return false;
+    }
+
+    // Do not demote across abs intrinsic; changing abs operand bitwidth alters semantics.
+    
     if (ID != Intrinsic::abs && ID != Intrinsic::smin &&
         ID != Intrinsic::smax && ID != Intrinsic::umin && ID != Intrinsic::umax)
       break;

